import{_ as a,o as s,c as n,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Quota & Suspension Problems","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/quotas.md","filePath":"troubleshooting/quotas.md"}'),t={name:"troubleshooting/quotas.md"};function i(r,e,l,u,p,c){return s(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="quota-suspension-problems" tabindex="-1">Quota &amp; Suspension Problems <a class="header-anchor" href="#quota-suspension-problems" aria-label="Permalink to &quot;Quota &amp; Suspension Problems&quot;">​</a></h1><p>This page is for the moments when the usage panel starts warning you, or a scope enters limited mode.</p><h2 id="_1-warning-banners" tabindex="-1">1. Warning banners <a class="header-anchor" href="#_1-warning-banners" aria-label="Permalink to &quot;1. Warning banners&quot;">​</a></h2><p>The usage panel has three warning levels:</p><ul><li><strong>80%</strong> means warning: you are getting close and should plan cleanup or more capacity soon.</li><li><strong>95%</strong> means critical: you are very close and should act before normal work gets blocked.</li><li><strong>100%</strong> means exceeded: new writes for that specific resource stop until space is freed or more capacity is granted.</li></ul><p>For the full user-side explanation, see <a href="./../subscriptions/quota-warnings.html">Quota Warnings &amp; Exceeded Limits</a>.</p><h2 id="_2-suspension-banner" tabindex="-1">2. Suspension banner <a class="header-anchor" href="#_2-suspension-banner" aria-label="Permalink to &quot;2. Suspension banner&quot;">​</a></h2><p>If you see a suspension or limited-mode banner:</p><ul><li>read access still remains</li><li>cleanup still remains available</li><li>new write actions are blocked</li></ul><p>Do not memorize the whole cascade model from this page. Use <a href="./../subscriptions/suspension.html">Suspension &amp; Limited Mode</a> for the details, especially if a kingdom suspension may affect alliances.</p><p>Who to ask:</p><ul><li><code>Alliance Leader</code> or <code>King</code> if you only need someone to review the situation</li><li><code>Supreme Admin</code> if the scope was manually suspended or must be unsuspended</li></ul><h2 id="_3-cleanup" tabindex="-1">3. Cleanup <a class="header-anchor" href="#_3-cleanup" aria-label="Permalink to &quot;3. Cleanup&quot;">​</a></h2><p>If the problem is usage-based, cleanup is the fastest path out.</p><p>Use:</p><ul><li><a href="./../subscriptions/cleanup.html">Run a Cleanup</a></li><li><a href="./../how-to/recycle-bin.html">Use the Recycle Bin</a></li><li><a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a></li></ul><p>If cleanup is not enough, the next step is a plan change or quota increase through <a href="./../subscriptions/request-subscription.html">Request a Subscription</a>.</p>',17)])])}const m=a(t,[["render",i]]);export{d as __pageData,m as default};
